func (j *JWTManager) TryStoreOrLoadJWTKeySecret() error {
	if j.clientset == nil {
		klog.Info("No Kubernetes client available, skipping JWT key secret management")
		return nil
	}

	ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
	defer cancel()

	secret, err := j.clientset.CoreV1().Secrets(j.namespace).Get(ctx, identitySecretName, metav1.GetOptions{})
	if err != nil {
		if apierrors.IsNotFound(err) {
			return j.createAndStoreKeys(ctx)
		}
		return fmt.Errorf("failed to get secret: %w", err)
	}

	return j.loadKeysFromSecret(secret)
}

func (j *JWTManager) createAndStoreKeys(ctx context.Context) error {
	privateKey, err := ecdsa.GenerateKey(elliptic.P256(), rand.Reader)
	if err != nil {
		return fmt.Errorf("failed to generate private key: %w", err)
	}

	privateKeyDER, err := x509.MarshalECPrivateKey(privateKey)
	if err != nil {
		return fmt.Errorf("failed to marshal private key: %w", err)
	}

	publicKeyDER, err := x509.MarshalPKIXPublicKey(&privateKey.PublicKey)
	if err != nil {
		return fmt.Errorf("failed to marshal public key: %w", err)
	}

	privateKeyPEM := pem.EncodeToMemory(&pem.Block{
		Type:  "EC PRIVATE KEY",
		Bytes: privateKeyDER,
	})

	publicKeyPEM := pem.EncodeToMemory(&pem.Block{
		Type:  "PUBLIC KEY",
		Bytes: publicKeyDER,
	})

	secret := &corev1.Secret{
		ObjectMeta: metav1.ObjectMeta{
			Name:      identitySecretName,
			Namespace: j.namespace,
		},
		Type: corev1.SecretTypeOpaque,
		Data: map[string][]byte{
			privateKeyPEMKey: privateKeyPEM,
			publicKeyPEMKey:  publicKeyPEM,
		},
	}

	_, err = j.clientset.CoreV1().Secrets(j.namespace).Create(ctx, secret, metav1.CreateOptions{})
	if err != nil {
		return fmt.Errorf("failed to create secret: %w", err)
	}

	j.privateKey = privateKey
	klog.Infof("Created JWT key secret %s/%s", j.namespace, identitySecretName)
	return nil
}

func (j *JWTManager) loadKeysFromSecret(secret *corev1.Secret) error {
	privateKeyPEM, ok := secret.Data[privateKeyPEMKey]
	if !ok {
		return errors.New("private key not found in secret")
	}

	block, _ := pem.Decode(privateKeyPEM)
	if block == nil {
		return errors.New("failed to decode private key PEM")
	}

	privateKey, err := x509.ParseECPrivateKey(block.Bytes)
	if err != nil {
		return fmt.Errorf("failed to parse private key: %w", err)
	}

	j.privateKey = privateKey
	klog.Infof("Loaded JWT keys from secret %s/%s", j.namespace, identitySecretName)
	return nil
}

func (j *JWTManager) GenerateToken() (string, error) {
	if j.privateKey == nil {
		return "", errors.New("private key not initialized")
	}

	now := time.Now()
	claims := JWTClaims{
		RegisteredClaims: jwt.RegisteredClaims{
			IssuedAt:  jwt.NewNumericDate(now),
			ExpiresAt: jwt.NewNumericDate(now.Add(jwtExpiration)),
			NotBefore: jwt.NewNumericDate(now),
		},
	}

	token := jwt.NewWithClaims(jwt.SigningMethodES256, claims)
	return token.SignedString(j.privateKey)
}

func (j *JWTManager) HasPrivateKey() bool {
	return j.privateKey != nil
}

