	"strings"

	"github.com/gin-gonic/gin"
	"k8s.io/klog/v2"

	"github.com/volcano-sh/agentcube/pkg/common/types"
)

const (
	forwardedHostHeader  = "X-Forwarded-Host"
	forwardedProtoHeader = "X-Forwarded-Proto"
	forwardedForHeader   = "X-Forwarded-For"
)

var sharedTransport = &http.Transport{
	Proxy: http.ProxyFromEnvironment,
	DialContext: (&net.Dialer{
		Timeout:   30 * time.Second,
		KeepAlive: 30 * time.Second,
	}).DialContext,
	MaxIdleConns:          100,
	IdleConnTimeout:       90 * time.Second,
	TLSHandshakeTimeout:   10 * time.Second,
	ExpectContinueTimeout: 1 * time.Second,
}

type Proxy struct {
	reverseProxy *httputil.ReverseProxy
	jwtManager   *JWTManager
	sandboxInfo  *types.SandboxInfo
	requestPath  string
}

func NewProxy(sandboxInfo *types.SandboxInfo, requestPath string, jwtMgr *JWTManager) (*Proxy, error) {
	if sandboxInfo == nil {
		return nil, errors.New("sandbox info is required")
	}

	if len(sandboxInfo.EntryPoints) == 0 {
		return nil, errors.New("no entry point found for sandbox")
	}

	entryPoint := findEntryPoint(sandboxInfo.EntryPoints, requestPath)

	upstreamURL, err := buildUpstreamURL(entryPoint)
	if err != nil {
		return nil, fmt.Errorf("failed to build upstream URL: %w", err)
	}

	proxy := httputil.NewSingleHostReverseProxy(upstreamURL)
	proxy.Transport = sharedTransport

	p := &Proxy{
		reverseProxy: proxy,
		jwtManager:   jwtMgr,
		sandboxInfo:  sandboxInfo,
		requestPath:  requestPath,
	}

	proxy.Director = p.createDirector(upstreamURL, entryPoint)
	proxy.ModifyResponse = p.modifyResponse
	proxy.ErrorHandler = p.errorHandler

	return p, nil
}

func findEntryPoint(entryPoints []types.SandboxEntryPoint, requestPath string) types.SandboxEntryPoint {
	for _, ep := range entryPoints {
		if requestPath != "" && strings.HasPrefix(requestPath, ep.Path) {
			return ep
		}
	}
	return entryPoints[0]
}

func buildUpstreamURL(entryPoint types.SandboxEntryPoint) (*url.URL, error) {
	endpoint := entryPoint.Endpoint

	if entryPoint.Protocol != "" && !strings.HasPrefix(strings.ToLower(endpoint), "http://") && !strings.HasPrefix(strings.ToLower(endpoint), "https://") {
		endpoint = fmt.Sprintf("%s://%s", strings.ToLower(entryPoint.Protocol), endpoint)
	}

	return url.Parse(endpoint)
}

func (p *Proxy) createDirector(upstreamURL *url.URL, entryPoint types.SandboxEntryPoint) func(*http.Request) {
	return func(req *http.Request) {
		req.URL.Scheme = upstreamURL.Scheme
		req.URL.Host = upstreamURL.Host

		targetPath := p.requestPath
		if targetPath != "" && !strings.HasPrefix(targetPath, "/") {
			targetPath = "/" + targetPath
		}

		req.URL.Path = targetPath
		req.URL.RawPath = targetPath

		req.Host = upstreamURL.Host

		p.setForwardingHeaders(req)

		if p.shouldInjectJWT() {
			token, err := p.jwtManager.GenerateToken()
			if err != nil {
				klog.Errorf("Failed to generate JWT token: %v", err)
				return
			}
			req.Header.Set("Authorization", fmt.Sprintf("Bearer %s", token))
		}
	}
}

func (p *Proxy) shouldInjectJWT() bool {
	kind := p.sandboxInfo.Kind
	return kind == types.SandboxKind || kind == types.SandboxClaimsKind
}

func (p *Proxy) setForwardingHeaders(req *http.Request) {
	if req.Host != "" {
		req.Header.Set(forwardedHostHeader, req.Host)
	}

	proto := "http"
	if req.TLS != nil {
		proto = "https"
	}
	req.Header.Set(forwardedProtoHeader, proto)

	clientIP := getClientIP(req)
	if existing := req.Header.Get(forwardedForHeader); existing != "" {
		req.Header.Set(forwardedForHeader, fmt.Sprintf("%s, %s", existing, clientIP))
	} else {
		req.Header.Set(forwardedForHeader, clientIP)
	}
}

func getClientIP(req *http.Request) string {
	if xff := req.Header.Get(forwardedForHeader); xff != "" {
		ips := strings.Split(xff, ",")
		if len(ips) > 0 {
			return strings.TrimSpace(ips[len(ips)-1])
		}
	}

	ip, _, err := net.SplitHostPort(req.RemoteAddr)
	if err != nil {
		return req.RemoteAddr
	}
	return ip
}

func (p *Proxy) modifyResponse(resp *http.Response) error {
	if p.sandboxInfo.SessionID != "" {
		resp.Header.Set(sessionIDHeader, p.sandboxInfo.SessionID)
	}
	return nil
}

func (p *Proxy) errorHandler(w http.ResponseWriter, r *http.Request, err error) {
	klog.Errorf("Proxy error: %v", err)

	errMsg := err.Error()
	status := http.StatusBadGateway
	errorBody := `{"error":"sandbox unreachable"}`

	if strings.Contains(errMsg, "timeout") {
		status = http.StatusGatewayTimeout
		errorBody = `{"error":"sandbox timeout"}`
	} else if strings.Contains(errMsg, "connection refused") {
		status = http.StatusBadGateway
	}

	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(status)
	w.Write([]byte(errorBody))
}

func (p *Proxy) ServeHTTP(w http.ResponseWriter, r *http.Request) {
	p.reverseProxy.ServeHTTP(w, r)
}

func forwardToSandbox(ctx context.Context, sandboxInfo *types.SandboxInfo, requestPath string, jwtMgr *JWTManager, c *gin.Context) error {
	proxy, err := NewProxy(sandboxInfo, requestPath, jwtMgr)
	if err != nil {
		return err
	}

	proxy.ServeHTTP(c.Writer, c.Request)
	return nil
}

