	"golang.org/x/net/http2/h2c"
	"k8s.io/klog/v2"

	"github.com/volcano-sh/agentcube/pkg/store"
)

type Server struct {
	config         *Config
	engine         *gin.Engine
	httpServer     *http.Server
	sessionManager SessionManager
	jwtManager     *JWTManager
	store          store.Store
}

func NewServer(cfg *Config) (*Server, error) {
	if cfg == nil {
		return nil, errors.New("config is required")
	}
	if err := cfg.Validate(); err != nil {
		return nil, fmt.Errorf("invalid config: %w", err)
	}

	if !cfg.Debug {
		gin.SetMode(gin.ReleaseMode)
	}

	engine := gin.New()

	jwtMgr, err := NewJWTManager()
	if err != nil {
		return nil, fmt.Errorf("failed to create JWT manager: %w", err)
	}

	if err := jwtMgr.TryStoreOrLoadJWTKeySecret(); err != nil {
		return nil, fmt.Errorf("failed to initialize JWT key: %w", err)
	}

	s := &Server{
		config:     cfg,
		engine:     engine,
		jwtManager: jwtMgr,
		store:      store.Storage(),
	}

	sm, err := NewSessionManager(s.store)
	if err != nil {
		return nil, fmt.Errorf("failed to create session manager: %w", err)
	}
	s.sessionManager = sm

	s.setupRoutes()

	s.httpServer = &http.Server{
		Addr:        fmt.Sprintf(":%d", cfg.Port),
		Handler:     h2c.NewHandler(engine, &http2.Server{}),
		ReadTimeout: 30 * time.Second,
		IdleTimeout: 90 * time.Second,
	}

	return s, nil
}

func (s *Server) Start(ctx context.Context) error {
	if s.config.EnableTLS {
		if s.config.TLSCert == "" || s.config.TLSKey == "" {
			return errors.New("TLS enabled but cert/key paths not provided")
		}
		klog.Infof("Starting HTTPS server on port %d", s.config.Port)
		return s.httpServer.ListenAndServeTLS(s.config.TLSCert, s.config.TLSKey)
	}

	klog.Infof("Starting HTTP server on port %d", s.config.Port)
	return s.httpServer.ListenAndServe()
}

func (s *Server) Shutdown(ctx context.Context) error {
	shutdownCtx, cancel := context.WithTimeout(ctx, 10*time.Second)
	defer cancel()
	return s.httpServer.Shutdown(shutdownCtx)
}

func (s *Server) GetEngine() *gin.Engine {
	return s.engine
}

func (s *Server) GetSessionManager() SessionManager {
	return s.sessionManager
}

func (s *Server) GetStore() store.Store {
	return s.store
}

func (s *Server) GetJWTManager() *JWTManager {
	return s.jwtManager
}

func getTLSState(r *http.Request) *tls.ConnectionState {
	if r == nil {
		return nil
	}
	return r.TLS
}

