	ErrEmptySessionID           = errors.New("empty session ID in response")
)

type SessionManager interface {
	GetSandboxBySession(ctx context.Context, sessionID, namespace, name, kind string) (*types.SandboxInfo, error)
	UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error
}

type manager struct {
	store              store.Store
	httpClient         *http.Client
	workloadManagerURL string
	authToken          string
}

func NewSessionManager(store store.Store) (SessionManager, error) {
	if store == nil {
		return nil, errors.New("store is required")
	}

	workloadManagerURL := os.Getenv(workloadManagerURLEnv)
	if workloadManagerURL == "" {
		return nil, ErrWorkloadManagerURLNotSet
	}

	authToken := ""
	if data, err := os.ReadFile(serviceAccountTokenPath); err == nil {
		authToken = strings.TrimSpace(string(data))
	}

	return &manager{
		store:              store,
		workloadManagerURL: workloadManagerURL,
		authToken:          authToken,
		httpClient: &http.Client{
			Timeout: 30 * time.Second,
			Transport: &http.Transport{
				TLSClientConfig: &tls.Config{
					InsecureSkipVerify: true,
				},
			},
		},
	}, nil
}

func (m *manager) GetSandboxBySession(ctx context.Context, sessionID, namespace, name, kind string) (*types.SandboxInfo, error) {
	if sessionID == "" {
		return m.createSandbox(ctx, namespace, name, kind)
	}

	sandbox, err := m.store.GetSandboxBySessionID(ctx, sessionID)
	if err != nil {
		if errors.Is(err, store.ErrNotFound) {
			return nil, api.NewSessionNotFoundError(sessionID)
		}
		return nil, err
	}

	return sandbox, nil
}

func (m *manager) createSandbox(ctx context.Context, namespace, name, kind string) (*types.SandboxInfo, error) {
	req := types.CreateSandboxRequest{
		Kind:      kind,
		Name:      name,
		Namespace: namespace,
	}

	reqBody, err := json.Marshal(req)
	if err != nil {
		return nil, fmt.Errorf("failed to marshal request: %w", err)
	}

	var endpoint string
	switch kind {
	case types.AgentRuntimeKind:
		endpoint = fmt.Sprintf("%s/v1/agent-runtime", m.workloadManagerURL)
	case types.CodeInterpreterKind:
		endpoint = fmt.Sprintf("%s/v1/code-interpreter", m.workloadManagerURL)
	default:
		return nil, fmt.Errorf("unknown kind: %s", kind)
	}

	httpReq, err := http.NewRequestWithContext(ctx, http.MethodPost, endpoint, bytes.NewReader(reqBody))
	if err != nil {
		return nil, fmt.Errorf("failed to create request: %w", err)
	}

	httpReq.Header.Set("Content-Type", "application/json")
	if m.authToken != "" {
		httpReq.Header.Set("Authorization", fmt.Sprintf("Bearer %s", m.authToken))
	}

	resp, err := m.httpClient.Do(httpReq)
	if err != nil {
		return nil, fmt.Errorf("failed to call workload manager: %w", err)
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		if resp.StatusCode == http.StatusNotFound {
			return nil, api.NewSandboxTemplateNotFoundError(namespace, name, kind)
		}
		body, _ := io.ReadAll(resp.Body)
		return nil, fmt.Errorf("workload manager returned status %d: %s", resp.StatusCode, string(body))
	}

	var createResp types.CreateSandboxResponse
	if err := json.NewDecoder(resp.Body).Decode(&createResp); err != nil {
		return nil, fmt.Errorf("failed to decode response: %w", err)
	}

	if createResp.SessionID == "" {
		return nil, ErrEmptySessionID
	}

	sandboxInfo := &types.SandboxInfo{
		Kind:        kind,
		SandboxID:   createResp.SandboxID,
		Name:        createResp.SandboxName,
		SessionID:   createResp.SessionID,
		EntryPoints: createResp.EntryPoints,
		CreatedAt:   time.Now(),
	}

	return sandboxInfo, nil
}

func (m *manager) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	return m.store.UpdateSessionLastActivity(ctx, sessionID, at)
}

