	workspace := t.TempDir()
	router, key := setupTestRouter(t, workspace)

	token := generateTestToken(t, key)

	body := `{"command": ["echo", "hello"]}`
	req := httptest.NewRequest(http.MethodPost, "/api/execute", bytes.NewBufferString(body))
	req.Header.Set("Authorization", "Bearer "+token)
	req.Header.Set("Content-Type", "application/json")
	w := httptest.NewRecorder()
	router.ServeHTTP(w, req)

	if w.Code != http.StatusOK {
		t.Errorf("Expected status %d, got %d: %s", http.StatusOK, w.Code, w.Body.String())
	}
}

func TestAuthMiddleware_ExpiredToken(t *testing.T) {
	workspace := t.TempDir()
	router, key := setupTestRouter(t, workspace)

	token := jwt.NewWithClaims(jwt.SigningMethodRS256, jwt.MapClaims{
		"sub": "test-user",
		"iat": time.Now().Add(-2 * time.Hour).Unix(),
		"exp": time.Now().Add(-time.Hour).Unix(),
	})

	tokenString, err := token.SignedString(key)
	if err != nil {
		t.Fatalf("Failed to sign token: %v", err)
	}

	body := `{"command": ["echo", "hello"]}`
	req := httptest.NewRequest(http.MethodPost, "/api/execute", bytes.NewBufferString(body))
	req.Header.Set("Authorization", "Bearer "+tokenString)
	req.Header.Set("Content-Type", "application/json")
	w := httptest.NewRecorder()
	router.ServeHTTP(w, req)

	if w.Code != http.StatusUnauthorized {
		t.Errorf("Expected status %d, got %d", http.StatusUnauthorized, w.Code)
	}
}

func TestHealthEndpoint_NoAuth(t *testing.T) {
	router, _ := setupTestRouter(t, t.TempDir())

	req := httptest.NewRequest(http.MethodGet, "/health", nil)
	w := httptest.NewRecorder()
	router.ServeHTTP(w, req)

	if w.Code != http.StatusOK {
		t.Errorf("Expected status %d, got %d", http.StatusOK, w.Code)
	}

	var resp HealthResponse
	if err := json.Unmarshal(w.Body.Bytes(), &resp); err != nil {
		t.Errorf("Failed to unmarshal response: %v", err)
	}

	if resp.Status != "ok" {
		t.Errorf("Expected status 'ok', got '%s'", resp.Status)
	}
	if resp.Service != "PicoD" {
		t.Errorf("Expected service 'PicoD', got '%s'", resp.Service)
	}
	if resp.Version != "0.0.1" {
		t.Errorf("Expected version '0.0.1', got '%s'", resp.Version)
	}
}

func TestLoadPublicKeyFromEnv_Missing(t *testing.T) {
	origEnv := os.Getenv(PublicKeyEnvVar)
	os.Unsetenv(PublicKeyEnvVar)
	defer os.Setenv(PublicKeyEnvVar, origEnv)

	_, err := LoadPublicKeyFromEnv()
	if err == nil {
		t.Error("Expected error when public key env var is missing")
	}
}

func TestLoadPublicKeyFromEnv_Invalid(t *testing.T) {
	t.Setenv(PublicKeyEnvVar, "invalid-pem-data")

	_, err := LoadPublicKeyFromEnv()
	if err == nil {
		t.Error("Expected error when public key is invalid")
	}
}

