				t.Errorf("NewServer() error = %v, wantErr %v", err, tt.wantErr)
			}
		})
	}
}

func TestServer_Routes(t *testing.T) {
	cfg := &Config{
		Port:                  8080,
		Debug:                 true,
		MaxConcurrentRequests: 100,
	}

	engine := gin.New()
	engine.GET("/health/live", handleHealthLive)
	engine.GET("/health/ready", handleHealthReady(nil))

	tests := []struct {
		name       string
		method     string
		path       string
		wantStatus int
	}{
		{
			name:       "health live endpoint",
			method:     http.MethodGet,
			path:       "/health/live",
			wantStatus: http.StatusOK,
		},
		{
			name:       "health ready endpoint - nil session manager",
			method:     http.MethodGet,
			path:       "/health/ready",
			wantStatus: http.StatusServiceUnavailable,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			req := httptest.NewRequest(tt.method, tt.path, nil)
			w := httptest.NewRecorder()

			engine.ServeHTTP(w, req)

			if w.Code != tt.wantStatus {
				t.Errorf("route %s returned status %d, want %d", tt.path, w.Code, tt.wantStatus)
			}
		})
	}
}

func TestServer_Shutdown(t *testing.T) {
	cfg := &Config{
		Port:                  0,
		Debug:                 true,
		MaxConcurrentRequests: 100,
	}

	engine := gin.New()
	server := &http.Server{
		Handler: engine,
	}

	shutdownCalled := make(chan bool, 1)
	go func() {
		time.Sleep(100 * time.Millisecond)
		ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
		defer cancel()
		_ = server.Shutdown(ctx)
		shutdownCalled <- true
	}()

	select {
	case <-shutdownCalled:
	case <-time.After(2 * time.Second):
		t.Error("shutdown did not complete in time")
	}
}

