func setupFilesTestRouter(t *testing.T, workspace string) (*gin.Engine, *rsa.PrivateKey) {
	t.Helper()
	gin.SetMode(gin.TestMode)

	key, err := rsa.GenerateKey(rand.Reader, 2048)
	if err != nil {
		t.Fatalf("Failed to generate RSA key: %v", err)
	}

	pubKeyBytes, err := jwt.MarshalRSAPublicKeyFromPEM(&key.PublicKey)
	if err != nil {
		t.Fatalf("Failed to marshal public key: %v", err)
	}
	t.Setenv(PublicKeyEnvVar, string(pubKeyBytes))

	authManager := NewAuthManager(&key.PublicKey)

	router := gin.New()
	RegisterRoutes(router, workspace, time.Now(), authManager)

	return router, key
}

func generateTestTokenForFiles(t *testing.T, key *rsa.PrivateKey) string {
	t.Helper()
	token := jwt.NewWithClaims(jwt.SigningMethodRS256, jwt.MapClaims{
		"sub": "test-user",
		"iat": time.Now().Unix(),
		"exp": time.Now().Add(time.Hour).Unix(),
	})

	tokenString, err := token.SignedString(key)
	if err != nil {
		t.Fatalf("Failed to sign token: %v", err)
	}

	return tokenString
}

func TestUploadFileHandler_JSON(t *testing.T) {
	workspace := t.TempDir()
	router, key := setupFilesTestRouter(t, workspace)
	token := generateTestTokenForFiles(t, key)

	content := base64.StdEncoding.EncodeToString([]byte("test content"))
	body := `{"path": "test.txt", "content": "` + content + `"}`
	req := httptest.NewRequest(http.MethodPost, "/api/files", bytes.NewBufferString(body))
	req.Header.Set("Authorization", "Bearer "+token)
	req.Header.Set("Content-Type", "application/json")
	w := httptest.NewRecorder()
	router.ServeHTTP(w, req)

	if w.Code != http.StatusOK {
		t.Errorf("Expected status %d, got %d: %s", http.StatusOK, w.Code, w.Body.String())
	}

	var resp FileInfo
	if err := json.Unmarshal(w.Body.Bytes(), &resp); err != nil {
		t.Errorf("Failed to unmarshal response: %v", err)
	}

	if resp.Path != "test.txt" {
		t.Errorf("Expected path 'test.txt', got '%s'", resp.Path)
	}

	data, err := os.ReadFile(filepath.Join(workspace, "test.txt"))
	if err != nil {
		t.Errorf("Failed to read file: %v", err)
	}
	if string(data) != "test content" {
		t.Errorf("Expected content 'test content', got '%s'", string(data))
	}
}

