func marshalPublicKeyPEM(t *testing.T, key *rsa.PrivateKey) string {
	t.Helper()
	pubKeyBytes, err := x509.MarshalPKIXPublicKey(&key.PublicKey)
	if err != nil {
		t.Fatalf("Failed to marshal public key: %v", err)
	}
	pubKeyPEM := pem.EncodeToMemory(&pem.Block{
		Type:  "PUBLIC KEY",
		Bytes: pubKeyBytes,
	})
	return string(pubKeyPEM)
}

func TestNewServer_MissingPublicKey(t *testing.T) {
	origEnv := os.Getenv(PublicKeyEnvVar)
	os.Unsetenv(PublicKeyEnvVar)
	defer os.Setenv(PublicKeyEnvVar, origEnv)

	cfg := &Config{
		Port:      "8080",
		Workspace: t.TempDir(),
	}

	_, err := NewServer(cfg)
	if err == nil {
		t.Error("Expected error when public key is missing")
	}
}

func TestNewServer_ValidPublicKey(t *testing.T) {
	key, err := rsa.GenerateKey(rand.Reader, 2048)
	if err != nil {
		t.Fatalf("Failed to generate RSA key: %v", err)
	}

	t.Setenv(PublicKeyEnvVar, marshalPublicKeyPEM(t, key))

	workspace := t.TempDir()
	cfg := &Config{
		Port:      "8080",
		Workspace: workspace,
	}

	server, err := NewServer(cfg)
	if err != nil {
		t.Errorf("Unexpected error: %v", err)
		return
	}

	if server == nil {
		t.Error("Expected server to be created")
		return
	}

	if server.config.Workspace != workspace {
		t.Errorf("Expected workspace %s, got %s", workspace, server.config.Workspace)
	}
}

