	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	err = server.Shutdown(ctx)
	if err != nil {
		t.Errorf("Unexpected error on shutdown: %v", err)
	}
}

func TestServer_RoutesRegistered(t *testing.T) {
	key, err := rsa.GenerateKey(rand.Reader, 2048)
	if err != nil {
		t.Fatalf("Failed to generate RSA key: %v", err)
	}

	t.Setenv(PublicKeyEnvVar, marshalPublicKeyPEM(t, key))

	workspace := t.TempDir()
	cfg := &Config{
		Port:      "8080",
		Workspace: workspace,
	}

	server, err := NewServer(cfg)
	if err != nil {
		t.Fatalf("Unexpected error: %v", err)
	}

	gin.SetMode(gin.TestMode)
	router := gin.New()
	RegisterRoutes(router, server.config.Workspace, server.startTime, server.authManager)

	token := jwt.NewWithClaims(jwt.SigningMethodRS256, jwt.MapClaims{
		"sub": "test-user",
		"iat": time.Now().Unix(),
		"exp": time.Now().Add(time.Hour).Unix(),
	})
	tokenString, _ := token.SignedString(key)

	tests := []struct {
		method string
		path   string
		auth   bool
	}{
		{"GET", "/health", false},
		{"POST", "/api/execute", true},
		{"POST", "/api/files", true},
		{"GET", "/api/files", true},
		{"GET", "/api/files/test.txt", true},
	}

	for _, tt := range tests {
		req := httptest.NewRequest(tt.method, tt.path, nil)
		if tt.auth {
			req.Header.Set("Authorization", "Bearer "+tokenString)
		}
		w := httptest.NewRecorder()
		router.ServeHTTP(w, req)

		if tt.method == "GET" && tt.path == "/health" {
			if w.Code != http.StatusOK {
				t.Errorf("Health endpoint should not require auth, got status %d", w.Code)
			}
		}
	}
}

func TestServer_HealthEndpointFormat(t *testing.T) {
	key, err := rsa.GenerateKey(rand.Reader, 2048)
	if err != nil {
		t.Fatalf("Failed to generate RSA key: %v", err)
	}

	t.Setenv(PublicKeyEnvVar, marshalPublicKeyPEM(t, key))

	workspace := t.TempDir()
	cfg := &Config{
		Port:      "8080",
		Workspace: workspace,
	}

	server, err := NewServer(cfg)
	if err != nil {
		t.Fatalf("Unexpected error: %v", err)
	}

	gin.SetMode(gin.TestMode)
	router := gin.New()
	RegisterRoutes(router, server.config.Workspace, server.startTime, server.authManager)

	req := httptest.NewRequest(http.MethodGet, "/health", nil)
	w := httptest.NewRecorder()
	router.ServeHTTP(w, req)

	var resp HealthResponse
	if err := json.Unmarshal(w.Body.Bytes(), &resp); err != nil {
		t.Errorf("Failed to unmarshal health response: %v", err)
	}

	if resp.Status != "ok" {
		t.Errorf("Expected status 'ok', got '%s'", resp.Status)
	}
	if resp.Service != "PicoD" {
		t.Errorf("Expected service 'PicoD', got '%s'", resp.Service)
	}
	if resp.Version != "0.0.1" {
		t.Errorf("Expected version '0.0.1', got '%s'", resp.Version)
	}
	if resp.Uptime == "" {
		t.Error("Expected non-empty uptime")
	}
}

