package picod

import (
	"errors"
	"path/filepath"
	"strings"
)

var (
	ErrPathEscapesWorkspace = errors.New("path escapes workspace jail")
	ErrEmptyWorkspace       = errors.New("workspace root is empty")
)

func sanitizePath(workspaceRoot, userPath string) (string, error) {
	if workspaceRoot == "" {
		return "", ErrEmptyWorkspace
	}

	absWorkspace, err := filepath.Abs(workspaceRoot)
	if err != nil {
		return "", err
	}

	targetPath := filepath.Join(absWorkspace, userPath)
	absTarget, err := filepath.Abs(targetPath)
	if err != nil {
		return "", err
	}

	if !strings.HasPrefix(absTarget, absWorkspace+string(filepath.Separator)) && absTarget != absWorkspace {
		return "", ErrPathEscapesWorkspace
	}

	return absTarget, nil
}

